    </span>
  );
}
ScrubBarTimeLabel.displayName = "ScrubBarTimeLabel";

export {
  ScrubBarContainer,
  ScrubBarTrack,
  ScrubBarProgress,
  ScrubBarThumb,
  ScrubBarTimeLabel,
};

